function connect(db) {
  if (!db) {
    throw new Error('panic: database is null');
  }
  return db.open();
}

def connect(db):
    if db is None:
        raise RuntimeError('panic: database is null')
    return db.open()

public void connect(Database db) {
    if (db == null) {
        throw new RuntimeException("panic: database is null");
    }
}

CREATE TRIGGER panic_check BEFORE INSERT ON transactions
FOR EACH ROW
BEGIN
  IF NEW.db_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'panic: invalid db';
  END IF;
END;
